 1→import React from 'react';
 2→
 3→import PropTypes from 'prop-types';
 4→
 5→import './button.css';
 6→
 7→/** Primary UI component for user interaction */
 8→export const Button = ({
 9→  primary = false,
10→  backgroundColor = null,
11→  size = 'medium',
12→  label,
13→  ...props
14→}) => {
15→  const mode = primary ? 'storybook-button--primary' : 'storybook-button--secondary';
16→  return (
17→    <button
18→      type="button"
19→      className={['storybook-button', `storybook-button--${size}`, mode].join(' ')}
20→      style={backgroundColor && { backgroundColor }}
21→      {...props}
22→    >
23→      {label}
24→    </button>
25→  );
26→};
27→
28→Button.propTypes = {
29→  /** Is this the principal call to action on the page? */
30→  primary: PropTypes.bool,
31→  /** What background color to use */
32→  backgroundColor: PropTypes.string,
33→  /** How large should the button be? */
34→  size: PropTypes.oneOf(['small', 'medium', 'large']),
35→  /** Button contents */
36→  label: PropTypes.string.isRequired,
37→  /** Optional click handler */
38→  onClick: PropTypes.func,
39→};
