import React from 'react';
import { MemoryRouter } from 'react-router-dom';
import { definePreview } from 'storybook/preview';
import '../src/core-ui/index.css';

export default definePreview({
  parameters: {
    controls: {
      matchers: {
        color: /(background|color)$/i,
        date: /Date$/i,
      },
    },
    a11y: {
      test: 'todo',
    },
  },
  decorators: [
    (Story) => (
      <MemoryRouter>
        <Story />
      </MemoryRouter>
    ),
  ],
});

import { fn } from 'storybook/test';
import { expect } from 'storybook/test';
import preview from '#.storybook/preview';
import Navigation from './Navigation';

const meta = preview.meta({
  component: Navigation,
  tags: ['ai-generated'],
  args: {
    loggedIn: false,
    setLoggedIn: fn(),
    setTriggeredLogout: fn(),
  },
});

export default meta;

export const LoggedOut = meta.story({
  args: {
    loggedIn: false,
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByText('Sign in')).toBeVisible();
    await expect(canvas.getByText('Sign up')).toBeVisible();
    await expect(canvas.getByAltText('Edgy')).toBeVisible();
  },
});

