  args: {
    loggedIn: true,
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByText('Sign out')).toBeVisible();
    await expect(canvas.getByText('Profile')).toBeVisible();
    await expect(canvas.getByAltText('Edgy')).toBeVisible();
  },
});

